import { Topic } from "@/types";

export const initialData: Topic[] = [
  {id:1,subject:'Constitutional Law – Commerce & Federal Power',rule:'Dormant Commerce Clause – Discriminatory State Laws',trigger:'State law explicitly discriminates against out-of-state commerce to protect local economic interests.',notes:'Triggers strict scrutiny. The state must prove the law is necessary to achieve an important, non-economic state interest (like health/safety) AND that there are no reasonable non-discriminatory alternatives available.',commonVsModern:'',date:new Date().toISOString()},
  {id:2,subject:'Constitutional Law – Commerce & Federal Power',rule:'Dormant Commerce Clause – Neutral State Laws',trigger:'State law is neutral on its face but incidentally burdens interstate commerce.',notes:'Subject to the Pike balancing test: The law is valid unless the burden on interstate commerce clearly outweighs the local benefits. Consider if less restrictive means could achieve the same goal.',commonVsModern:'',date:new Date().toISOString()},
  {id:3,subject:'Constitutional Law – Commerce & Federal Power',rule:'Supremacy Clause – Express Preemption',trigger:'A federal statute explicitly states that it preempts state or local law.',notes:'This is the clearest form of preemption. The federal law dictates exactly which state laws are preempted. Courts will look at the explicit language of the statute.',commonVsModern:'',date:new Date().toISOString()},
  {id:4,subject:'Constitutional Law – Commerce & Federal Power',rule:'Supremacy Clause – Field Preemption',trigger:'Federal regulation is so pervasive that it leaves no room for state regulation in that area.',notes:'Even if the federal statute is silent on preemption, courts infer Congress intended to "occupy the field" (e.g., immigration or bankruptcy). Any state law in this field, even if consistent with federal law, is preempted.',commonVsModern:'',date:new Date().toISOString()},
  {id:5,subject:'Constitutional Law – Commerce & Federal Power',rule:'Supremacy Clause – Conflict Preemption',trigger:'State law directly conflicts with federal law, making it impossible to comply with both, or frustrating federal purposes.',notes:'If physical compliance with both is impossible, federal law wins. Additionally, if the state law stands as an obstacle to the accomplishment of the federal objective, it is preempted.',commonVsModern:'',date:new Date().toISOString()},
  {id:6,subject:'Constitutional Law – Commerce & Federal Power',rule:'Congress Taxing Power',trigger:'A federal tax is challenged as being outside Congressional power.',notes:'A tax is valid if it bears some reasonable relationship to revenue production OR if Congress has the power to regulate the taxed activity. It cannot be purely a "penalty" lacking a revenue-raising feature.',commonVsModern:'',date:new Date().toISOString()},
  {id:7,subject:'Constitutional Law – Individual Rights',rule:'Equal Protection – Levels of Scrutiny',trigger:'A government classification treats groups of persons differently.',notes:'Strict Scrutiny (necessary to achieve a compelling interest): suspect classes or fundamental rights. Intermediate Scrutiny (substantially related to important interest): quasi-suspect classes. Rational Basis (rationally related to legitimate interest): all others.',commonVsModern:'',date:new Date().toISOString()},
  {id:8,subject:'Constitutional Law – Individual Rights',rule:'Equal Protection – Suspect & Quasi-Suspect Classes',trigger:'Classification based on race, gender, legitimacy, or alienage.',notes:'Suspect (Strict Scrutiny): Race, national origin, alienage (with exceptions for state self-government/democratic process). Quasi-suspect (Intermediate Scrutiny): Gender, non-marital children (legitimacy). Discriminatory intent is required, not just disproportionate impact.',commonVsModern:'',date:new Date().toISOString()},
  {id:9,subject:'Constitutional Law – Individual Rights',rule:'State Action Doctrine',trigger:'An alleged constitutional violation is committed by a private actor.',notes:'Constitutional rights generally apply only against government action. Exceptions where private actors are bound: (1) Public Function (performing a task traditionally and exclusively done by gov\'t) and (2) Entanglement (significant gov\'t involvement/encouragement/enforcement).',commonVsModern:'',date:new Date().toISOString()},
  {id:10,subject:'Constitutional Law – Individual Rights',rule:'First Amendment – Forum Types',trigger:'Government restricts speech in a government-owned space.',notes:'Traditional Public Forum (streets/parks): Strict scrutiny for content-based; intermediate for time/place/manner. Designated Public Forum: Same as traditional. Nonpublic Forum (military bases/schools): Restrictions must be viewpoint-neutral and reasonably related to a legitimate gov\'t purpose.',commonVsModern:'',date:new Date().toISOString()},
  {id:11,subject:'Constitutional Law – Individual Rights',rule:'First Amendment – Content-Based vs Neutral',trigger:'Government regulates speech on public property or generally.',notes:'Content-based restrictions target the topic or viewpoint and trigger strict scrutiny (must be necessary for a compelling interest). Content-neutral restrictions (Time, Place, Manner) trigger intermediate scrutiny (must serve important interest and leave open alternative channels).',commonVsModern:'',date:new Date().toISOString()},
  {id:12,subject:'Constitutional Law – Justiciability',rule:'Standing – Three-Part Test',trigger:'Plaintiff sues in federal court under Article III.',notes:'(1) Injury in fact: Concrete and particularized, actual or imminent. (2) Causation: The injury must be fairly traceable to the defendant\'s conduct. (3) Redressability: A favorable court decision must be likely to remedy the injury.',commonVsModern:'',date:new Date().toISOString()},
  {id:13,subject:'Constitutional Law – Justiciability',rule:'Ripeness',trigger:'Plaintiff challenges a government action or statute before it has been enforced against them.',notes:'The claim must be ready for judicial decision. Courts look at (1) the fitness of the issues for judicial decision (purely legal issues are better) and (2) the hardship to the parties if the court withholds consideration.',commonVsModern:'',date:new Date().toISOString()},
  {id:14,subject:'Constitutional Law – Justiciability',rule:'Mootness',trigger:'Plaintiff\'s injury is resolved or disappears after the suit is filed.',notes:'If there is no longer an ongoing case or controversy, the case is moot. Exceptions: Wrongs capable of repetition yet evading review (e.g., pregnancy), voluntary cessation by defendant (but can resume), and class action suits where lead plaintiff\'s claim becomes moot.',commonVsModern:'',date:new Date().toISOString()},
  {id:15,subject:'Constitutional Law – Commerce & Federal Power',rule:'Eleventh Amendment / State Sovereign Immunity',trigger:'A citizen sues a state in federal or state court.',notes:'Bars suits against states for money damages. Exceptions: (1) State consents/waives, (2) Ex parte Young (suing state official for prospective injunctive relief), (3) Congress clearly abrogates immunity under Section 5 of the 14th Amendment.',commonVsModern:'',date:new Date().toISOString()},
  {id:16,subject:'Civil Procedure',rule:'Summary Judgment Standard (Rule 56)',trigger:'Party moves for summary judgment before trial, arguing no trial is needed.',notes:'Granted when the movant shows there is "no genuine dispute as to any material fact" AND the movant is "entitled to judgment as a matter of law." The court views all evidence in the light most favorable to the non-moving party.',commonVsModern:'',date:new Date().toISOString()},
  {id:17,subject:'Civil Procedure',rule:'Judgment as a Matter of Law (JMOL) (Rule 50)',trigger:'Party moves during trial (after opponent\'s case) or after trial (Renewed JMOL).',notes:'Standard: The court finds that a "reasonable jury would not have a legally sufficient evidentiary basis" to find for the non-movant. To file a Renewed JMOL after the verdict, the party MUST have filed an initial JMOL motion before the case went to the jury.',commonVsModern:'',date:new Date().toISOString()},
  {id:18,subject:'Civil Procedure',rule:'Appellate Standards of Review',trigger:'An appellate court reviews a trial court\'s decision.',notes:'Questions of Law (e.g., jury instructions, summary judgment): De Novo (no deference). Questions of Fact decided by a judge: Clear Error. Discretionary rulings (e.g., admitting evidence, granting extensions): Abuse of Discretion.',commonVsModern:'',date:new Date().toISOString()},
  {id:19,subject:'Constitutional Law – Individual Rights',rule:'Procedural Due Process',trigger:'The government intentionally deprives a person of life, liberty, or property.',notes:'Must provide notice and a hearing. To determine what process is due, use the Mathews balancing test: (1) Importance of the individual interest, (2) Risk of erroneous deprivation and value of additional safeguards, and (3) Government\'s interest (efficiency/cost).',commonVsModern:'',date:new Date().toISOString()},
  {id:20,subject:'Contracts',rule:'Discharge by Death – Personal Services',trigger:'A party to a contract dies before performance is complete.',notes:'Generally, death does NOT discharge contractual duties (the estate must perform or pay). EXCEPTION: Contracts for personal services (where the person has special skills or was specifically chosen) are discharged upon that person\'s death because the duties cannot be delegated.',commonVsModern:'',date:new Date().toISOString()},
  {id:21,subject:'Torts',rule:'Strict Products Liability – Proper Defendants',trigger:'A plaintiff is injured by a defective product and sues those in the distribution chain.',notes:'Strict liability applies ONLY to "commercial suppliers" (manufacturers, wholesalers, retailers) who routinely deal in the product. It does NOT apply to casual sellers (e.g., selling your used lawnmower) or service providers using the product (e.g., a dentist using a defective tool).',commonVsModern:'',date:new Date().toISOString()},
  {id:22,subject:'Torts',rule:'Intentional Infliction of Emotional Distress (IIED)',trigger:'Defendant engages in extreme and outrageous conduct causing emotional harm.',notes:'Elements: (1) Extreme and outrageous conduct (transcends all bounds of decency), (2) Intent or recklessness, (3) Causation, (4) Severe emotional distress. Unlike other intentional torts, actual severe damage must be proven (though physical injury is not required).',commonVsModern:'',date:new Date().toISOString()},
  {id:23,subject:'Real Property',rule:'Easements Appurtenant and Recording',trigger:'An easement benefits one parcel of land (dominant estate) and burdens another (servient estate).',notes:'The benefit of an appurtenant easement passes automatically with the transfer of the dominant estate. The burden passes with the servient estate UNLESS the new owner is a bona fide purchaser (BFP) without notice (actual, constructive/recorded, or inquiry/visible).',commonVsModern:'',date:new Date().toISOString()},
  {id:24,subject:'Real Property',rule:'Recording Acts – Notice Statute',trigger:'Multiple parties claim an interest in the same property; subsequent purchaser enters the picture.',notes:'"A conveyance... shall not be valid against any subsequent purchaser for value, without notice thereof, unless the conveyance is recorded." Under a notice statute, the subsequent BFP prevails if they had no notice (actual, record, or inquiry) of the prior interest at the time they purchased.',commonVsModern:'',date:new Date().toISOString()},
  {id:25,subject:'Evidence',rule:'Confrontation Clause vs Non-Testimonial Evidence',trigger:'Prosecution offers an out-of-court statement against a criminal defendant, and the declarant is unavailable.',notes:'Under the 6th Amendment, "testimonial" hearsay is inadmissible unless the defendant had a prior opportunity to cross-examine. Testimonial = statements made for primary purpose of establishing past events for prosecution (e.g., police interrogations after emergency ends, affidavits). Non-testimonial = addressing ongoing emergency, business records.',commonVsModern:'',date:new Date().toISOString()},
  {id:26,subject:'Evidence',rule:'Best Evidence Rule',trigger:'A party attempts to prove the contents of a writing, recording, or photograph.',notes:'Applies only when the document is legally operative (like a contract or deed) or the witness is testifying solely from having read the document. Requires the original or a reliable duplicate. Oral testimony is insufficient unless the proponent proves the original was lost/destroyed in good faith.',commonVsModern:'',date:new Date().toISOString()},
  {id:27,subject:'Evidence',rule:'Impeachment – Bias and Motive to Lie',trigger:'Cross-examination or extrinsic evidence showing a witness has a motive to testify falsely (e.g., plea deal, relationship, financial interest).',notes:'Bias is always relevant and is a highly tested proper form of impeachment. Unlike some prior bad acts, if a witness denies bias on cross-examination, you CAN introduce extrinsic evidence (like another witness or document) to prove the bias exists.',commonVsModern:'',date:new Date().toISOString()},
  {id:28,subject:'Criminal Law',rule:'Embezzlement – Value of Property',trigger:'Defendant legally possessed funds or property but then converted it for their own use, and the value changed.',notes:'Embezzlement is the fraudulent conversion of property by one in lawful possession. The relevant amount/value for grading the offense is the value at the time of the conversion, not any later increased value or the amount returned.',commonVsModern:'',date:new Date().toISOString()},
  {id:29,subject:'Torts',rule:'Negligence Per Se',trigger:'Defendant violates a criminal or regulatory statute, causing an injury to plaintiff.',notes:'The statutory duty replaces the general duty of care. To apply, Plaintiff must show: (1) they are in the class of persons the statute was designed to protect, and (2) the harm suffered is the type of harm the statute was designed to prevent. Violation establishes duty and breach (but not causation).',commonVsModern:'',date:new Date().toISOString()},
  {id:30,subject:'Torts',rule:'Safety Ordinances – Standard of Care',trigger:'Defendant violates a local safety ordinance (e.g., building code, traffic rule).',notes:'Similar to negligence per se, an unexcused violation of a safety statute/ordinance establishes breach of duty. Excuses include: compliance would be more dangerous than non-compliance, or compliance is impossible despite reasonable efforts.',commonVsModern:'',date:new Date().toISOString()},
  {id:31,subject:'Torts',rule:'Ambiguity in Statutory Terms',trigger:'A statute used for Negligence Per Se has ambiguous language.',notes:'When applying negligence per se, courts interpret ambiguous terms in light of the statute\'s underlying purpose. If the statute\'s purpose does not align with the plaintiff\'s injury, negligence per se does not apply, and plaintiff must prove standard negligence.',commonVsModern:'',date:new Date().toISOString()},
  {id:32,subject:'Evidence',rule:'Business Records Hearsay Exception',trigger:'A party offers a business ledger, medical record, or corporate log to prove the truth of its contents.',notes:'FRE 803(6) Exception requires: record made at/near the time of the event, by someone with knowledge (or from information transmitted by them), kept in the regular course of business, and making the record was a regular practice. Must be authenticated by a custodian/qualified witness.',commonVsModern:'',date:new Date().toISOString()},
  {id:33,subject:'Evidence',rule:'Requirements for Business Record Admissibility',trigger:'A party offers a business record but an opponent argues it was prepared for litigation.',notes:'Documents prepared primarily for litigation (e.g., an accident report created by the defendant for their lawyers) do NOT qualify for the business records exception because they lack the reliability of routine business administration. The opponent must show lack of trustworthiness.',commonVsModern:'',date:new Date().toISOString()},
  {id:34,subject:'Evidence',rule:'Missing Foundational Facts for Business Records',trigger:'A business record is offered, but the sponsoring witness doesn\'t know how or when it was created.',notes:'If the proponent fails to establish all foundational elements (time, knowledge, regular practice) through a custodian or qualified witness (or a proper certification), the record is inadmissible hearsay. The witness doesn\'t need to have made the record, just know how the business creates them.',commonVsModern:'',date:new Date().toISOString()},
  {id:35,subject:'Business Entities',rule:'Partnership Liability in Litigation',trigger:'Plaintiff sues a general partnership and wants to collect from the personal assets of the partners.',notes:'While partners are jointly and severally liable for partnership obligations, a judgment creditor generally cannot execute against a partner\'s personal assets unless the creditor has also obtained a judgment against the partner individually AND partnership assets are exhausted.',commonVsModern:'',date:new Date().toISOString()},
  {id:36,subject:'Business Entities',rule:'LLP vs General Partnership Liability',trigger:'A tort occurs in an LLP or GP; the plaintiff sues the partners.',notes:'In a General Partnership (GP), all partners are personally liable for the torts of other partners committed in the ordinary course of business. In a Limited Liability Partnership (LLP), partners are NOT personally liable for the obligations of the LLP or the torts of other partners (they are only liable for their own torts).',commonVsModern:'',date:new Date().toISOString()},
  {id:37,subject:'Constitutional Law – Criminal Procedure',rule:'Fourth Amendment – Forcible Entry with Arrest Warrant',trigger:'Police have an arrest warrant and go to the suspect\'s home to execute it.',notes:'An arrest warrant implicitly authorizes entry into the suspect\'s own home if there is reason to believe they are inside. However, police must generally "knock and announce" their presence unless there are exigent circumstances (threat of violence, destruction of evidence).',commonVsModern:'',date:new Date().toISOString()},
  {id:38,subject:'Constitutional Law – Criminal Procedure',rule:'Fourth Amendment – Consent Exception',trigger:'Police seek to search a residence or room and ask for consent.',notes:'Consent must be voluntary and given by someone with actual or apparent authority. Co-occupants can consent to shared areas. Hotel staff cannot consent to a search of a guest\'s room while they are renting it, but once the guest checks out, the hotel regains authority to consent.',commonVsModern:'',date:new Date().toISOString()},
  {id:39,subject:'Constitutional Law – Criminal Procedure',rule:'Fifth Amendment – Miranda / Custodial Interrogation',trigger:'Police question a suspect without giving Miranda warnings.',notes:'Miranda warnings are ONLY required when a suspect is in "custody" (not free to leave, environment is police-dominated) AND subjected to "interrogation" (words/actions reasonably likely to elicit an incriminating response). Routine booking questions and Terry stops do not require Miranda.',commonVsModern:'',date:new Date().toISOString()},
  {id:40,subject:'Criminal Law',rule:'Affirmative Defenses – Burden of Proof',trigger:'Defendant claims self-defense, insanity, or duress.',notes:'The prosecution must always prove every element of the crime beyond a reasonable doubt. However, states can constitutionally place the burden of persuasion (proving the defense by a preponderance of the evidence) on the defendant for affirmative defenses like insanity or duress.',commonVsModern:'Common Law / Traditional Rule: The prosecution had to disprove affirmative defenses (like insanity) beyond a reasonable doubt.\\nModern Law: States can constitutionally shift the burden of persuasion to the defendant for affirmative defenses (usually by a preponderance of the evidence or clear and convincing evidence).\\nScenarios: Look for questions asking about the constitutionality of a statute shifting the burden of an affirmative defense to the defendant. It is constitutional.',date:new Date().toISOString()},
  {id:41,subject:'Criminal Law',rule:'Forgery vs False Pretenses',trigger:'Defendant uses a fake document or lies to get property.',notes:'Forgery: Making or altering a document of legal significance (check, contract) with intent to defraud. False Pretenses: Obtaining title to property of another by an intentional false statement of past or existing fact, with intent to defraud.',commonVsModern:'',date:new Date().toISOString()},
  {id:42,subject:'Criminal Law',rule:'Accomplice Liability for Battery',trigger:'Defendant encourages or orders another person to hit someone.',notes:'An accomplice aids, abets, or encourages the principal with the intent that the crime be committed. The accomplice is liable for the target crime (battery) and any other crimes that are natural and probable consequences of the target crime.',commonVsModern:'',date:new Date().toISOString()},
  {id:43,subject:'Criminal Law',rule:'Attempted Robbery vs Robbery',trigger:'Defendant tries to take property by force but fails to get it.',notes:'Robbery requires a taking and carrying away of personal property from another\'s person/presence by force or threat, with intent to permanently deprive. If the defendant doesn\'t successfully complete the taking (e.g., victim runs away, defendant is tackled), it is Attempted Robbery, which requires specific intent and a substantial step.',commonVsModern:'',date:new Date().toISOString()},
  {id:44,subject:'Criminal Law',rule:'Felony Murder',trigger:'A death occurs during the commission of a felony.',notes:'Any killing (even accidental) committed during the commission of or attempt to commit an inherently dangerous felony (Burglary, Arson, Rape, Robbery, Kidnapping - BARRK). The underlying felony must be independent of the killing (e.g., aggravated battery cannot be the underlying felony).',commonVsModern:'',date:new Date().toISOString()},
  {id:45,subject:'Constitutional Law – Individual Rights',rule:'First Amendment – Time, Place, Manner Restrictions',trigger:'A city passes an ordinance restricting parades, noise, or sign sizes in public areas.',notes:'To be valid, the restriction must be content-neutral, narrowly tailored to serve a significant government interest (like traffic control or aesthetics), and leave open ample alternative channels of communication. It does NOT need to be the least restrictive means.',commonVsModern:'',date:new Date().toISOString()},
  {id:46,subject:'Constitutional Law – Individual Rights',rule:'First Amendment – Sexually Explicit Non-Obscene Material',trigger:'The government attempts to ban or restrict indecent but not legally obscene material (e.g., on the internet).',notes:'Indecent speech is protected. Obscenity is not. To restrict access to protected indecent material (to protect minors, for example), the government must use the least restrictive means (e.g., age-verification, filters) rather than a total ban that infringes on adults\' rights.',commonVsModern:'',date:new Date().toISOString()},
  {id:47,subject:'Civil Procedure',rule:'Rule 11 Sanctions Safe Harbor',trigger:'A party files a frivolous motion or pleading; the opponent wants sanctions.',notes:'Under Rule 11, before filing a motion for sanctions with the court, the party must serve the motion on the opponent and give them a 21-day "safe harbor" period to withdraw or correct the challenged paper. If they fix it, the motion cannot be filed.',commonVsModern:'',date:new Date().toISOString()},
  {id:48,subject:'Civil Procedure',rule:'Initial Disclosure Requirements (Rule 26(a)(1))',trigger:'The start of discovery in a civil case.',notes:'Parties must automatically disclose: names/contact info of individuals with discoverable information that the disclosing party may use to support its claims/defenses, copies/descriptions of documents to be used for support, computation of damages, and insurance agreements. You do NOT have to disclose bad evidence that hurts your case during initial disclosures.',commonVsModern:'',date:new Date().toISOString()},
  {id:49,subject:'Civil Procedure',rule:'Amending Pleadings as Matter of Course (Rule 15)',trigger:'A plaintiff realizes they forgot a claim and wants to amend the complaint.',notes:'A party has an absolute right to amend their pleading once within 21 days of serving it, OR within 21 days of service of a responsive pleading or a Rule 12(b) motion. After this period expires, they need the opponent\'s written consent or the court\'s leave (which is freely given when justice requires).',commonVsModern:'',date:new Date().toISOString()},
  {id:50,subject:'Real Property',rule:'Lease Assignments vs Subleases',trigger:'A tenant transfers their lease to a third party.',notes:'Assignment: Tenant transfers the ENTIRE remaining term. Assignee is in privity of estate with the landlord (liable for rent/covenants). Sublease: Tenant transfers LESS than the entire remaining term. Sublessee is NOT in privity of estate with landlord (original tenant remains solely liable to landlord).',commonVsModern:'',date:new Date().toISOString()},
  {id:51,subject:'Real Property',rule:'Real Covenants – Affirmative vs Negative',trigger:'A deed includes a promise regarding the use of land.',notes:'A covenant is a promise to do (affirmative) or not do (negative) something on the land. For the burden to run with the land to a successor, there must be Writing, Intent, Touch and Concern, Horizontal and Vertical Privity, and Notice. (WITHN). For the benefit to run, you only need WITV (no horizontal privity or notice required).',commonVsModern:'',date:new Date().toISOString()},
  {id:52,subject:'Constitutional Law – Criminal Procedure',rule:'Fourth Amendment – Knock-and-Announce Rule Violation',trigger:'Police have a valid warrant, but bust down the door without knocking.',notes:'While police are required to knock and announce, a violation of this rule does NOT trigger the exclusionary rule. Evidence found in the subsequent search is still admissible. The suspect\'s remedy is a civil suit.',commonVsModern:'',date:new Date().toISOString()},
  {id:53,subject:'Constitutional Law – Criminal Procedure',rule:'Fourth Amendment – Exigent Circumstances Exception',trigger:'Police hear screaming or toilets flushing inside a house and enter without a warrant.',notes:'Warrantless entry is justified by exigent circumstances: hot pursuit of a fleeing felon, imminent destruction of evidence, or emergency aid (protecting someone from imminent injury). The police must have probable cause to enter.',commonVsModern:'',date:new Date().toISOString()},
  {id:54,subject:'Constitutional Law – Criminal Procedure',rule:'Fourth Amendment – Authority to Consent After Checkout',trigger:'Police want to search a hotel room after the checkout time.',notes:'A hotel guest has a reasonable expectation of privacy in their room during the rental period. Once the rental period expires and the guest checks out (or is lawfully evicted), that expectation ends, and the hotel manager can validly consent to a police search of the room.',commonVsModern:'',date:new Date().toISOString()},
  {id:55,subject:'Constitutional Law – Criminal Procedure',rule:'Fifth Amendment – Traffic Stop as Custody',trigger:'A police officer stops a car for speeding and asks the driver questions.',notes:'A routine traffic stop (a Terry stop of a car) is NOT considered "custody" for Miranda purposes, because it is temporary and relatively brief. Thus, statements made by the driver during the stop are admissible even without Miranda warnings, unless the stop escalates into an arrest.',commonVsModern:'',date:new Date().toISOString()},
  {id:56,subject:'Constitutional Law – Criminal Procedure',rule:'Fifth Amendment – Suppression of Unwarned Statements',trigger:'Police interrogate an arrested suspect without reading Miranda, getting a confession and finding the murder weapon.',notes:'The unwarned confession is inadmissible in the prosecution\'s case-in-chief (but can be used for impeachment). However, physical evidence found as a result of a voluntary unwarned statement is NOT suppressed (Miranda has no "fruit of the poisonous tree" doctrine for physical evidence).',commonVsModern:'',date:new Date().toISOString()},
  {id:57,subject:'Criminal Law',rule:'Duress – Burden of Persuasion',trigger:'Defendant committed a robbery but claims someone held a gun to his head.',notes:'Duress is an affirmative defense (threat of imminent death/great bodily harm causing the defendant to commit the crime). It is valid for all crimes EXCEPT intentional homicide. The burden can be placed on the defendant to prove duress by a preponderance of the evidence.',commonVsModern:'',date:new Date().toISOString()},
  {id:58,subject:'Criminal Law',rule:'Forgery – Document of Legal Significance',trigger:'Defendant signs a celebrity\'s autograph and sells it, vs signing someone else\'s check.',notes:'Forgery requires making or altering a writing so that it is false, with intent to defraud. The writing must be one that has apparent legal significance (e.g., a check, deed, will, contract). A mere autograph or painting does not have legal significance for forgery.',commonVsModern:'',date:new Date().toISOString()},
  {id:59,subject:'Criminal Law',rule:'False Pretenses – Victim Passes Title',trigger:'Defendant tricks someone into giving them ownership of property (e.g., by using fake cash to buy a car).',notes:'Unlike Larceny by Trick (where victim only gives possession), False Pretenses requires that the victim intended to pass TITLE (ownership) to the defendant, based on the defendant\'s intentional false representation of a material fact.',commonVsModern:'',date:new Date().toISOString()},
  {id:60,subject:'Criminal Law',rule:'Accomplice – Ordering Unlawful Force',trigger:'A gang leader orders a member to beat someone up.',notes:'The person giving the order is liable as an accomplice. If the principal goes further and kills the victim, the accomplice is also liable for murder if it was a foreseeable result of the ordered beating.',commonVsModern:'',date:new Date().toISOString()},
  {id:61,subject:'Criminal Law',rule:'Robbery – Taking vs Failed Endorsement',trigger:'Defendant forces someone to hand over a check but runs away before making them endorse it.',notes:'Without the endorsement, the check cannot be cashed, but a taking still occurred. Property is "taken" when the defendant gains control over it. Even brief control satisfies the taking element for robbery or larceny.',commonVsModern:'',date:new Date().toISOString()},
  {id:62,subject:'Criminal Law',rule:'Felony Murder – Underlying Act Must Be Felony',trigger:'Defendant commits a misdemeanor assault that accidentally results in death.',notes:'If the underlying crime is not a qualifying dangerous felony, Felony Murder does not apply. Instead, look to Involuntary Manslaughter (unlawful act manslaughter or criminal negligence).',commonVsModern:'',date:new Date().toISOString()},
  {id:63,subject:'Torts',rule:'Modern Landowner Duty of Care',trigger:'A guest, a plumber, and a trespasser are injured on a landowner\'s property.',notes:'A majority of states still use traditional categories (Invitee = reasonable care, Licensee = warn of known hidden dangers, Trespasser = no duty to unknown). However, the MODERN trend (tested on the bar) abolishes the invitee/licensee distinction, applying a single reasonable-care standard to all lawful entrants. Known/foreseeable trespassers must be warned of highly dangerous artificial conditions.',commonVsModern:'Common Law: Categorized entrants rigidly (Invitee, Licensee, Trespasser) and duty depended entirely on status. \\nModern Law: Abolishes distinctions for lawful entrants (Invitee/Licensee) and applies a universal reasonable-care standard. \\nScenarios: If a question mentions a specific jurisdiction type (e.g., \'in a jurisdiction following traditional rules\'), use the categories. If it asks under the modern trend or UBE default trend, apply reasonable care to all lawful guests.',date:new Date().toISOString()},
  {id:64,subject:'Constitutional Law – Individual Rights',rule:'Free Exercise Clause & Ministerial Exception',trigger:'A church fires a priest for discriminatory reasons (e.g., age or gender).',notes:'The First Amendment "ministerial exception" categorically bars employment discrimination suits brought by ministers against their religious employers. This protects religious groups\' right to choose their spiritual leaders free from government interference.',commonVsModern:'',date:new Date().toISOString()},
  {id:65,subject:'Civil Procedure',rule:'Venue and Transfer (28 U.S.C. 1404)',trigger:'A lawsuit is filed in a proper venue, but the defendant wants it moved.',notes:'Proper venue is where any defendant resides (if all live in the same state) OR where a substantial part of the events occurred. Even if venue is proper, a court may transfer the case to another proper venue for the convenience of parties and witnesses, and in the interest of justice. The new court applies the choice-of-law rules of the original court.',commonVsModern:'',date:new Date().toISOString()},
  {id:66,subject:'Contracts',rule:'Formation and Quantity Term under UCC',trigger:'Merchants agree to buy/sell widgets, but leave price and delivery date blank.',notes:'Under UCC Article 2, a contract can be formed even with missing terms (gap fillers for price, delivery, time). HOWEVER, the "quantity" term cannot be filled by the court; it must be stated. The only exception is requirements or output contracts, which measure quantity by the buyer\'s needs or seller\'s output in good faith.',commonVsModern:'Common Law: Required all essential terms (price, subject, quantity, time) to be specified. No gap fillers.\\nModern Law (UCC Article 2): Extremely flexible. Only quantity is strictly required. The court will gap-fill price and delivery.\\nScenarios: If the contract is for services (Common Law), a missing price means the contract might fail for indefiniteness. If it is for goods (UCC), a missing price is perfectly fine and gap-filled as a reasonable price at delivery.',date:new Date().toISOString()},
  {id:67,subject:'Evidence',rule:'Authentication of Physical Evidence (FRE 901)',trigger:'A party tries to introduce a gun, document, or photo into evidence.',notes:'The proponent must produce evidence sufficient to support a finding that the item is what the proponent claims it is. This is a low bar. It can be satisfied by testimony from a witness with personal knowledge (e.g., "I recognize this gun by the scratch on the barrel"). A strict chain of custody is only needed for generic, fungible items (like bags of white powder).',commonVsModern:'',date:new Date().toISOString()},
  {id:68,subject:'Constitutional Law – Criminal Procedure',rule:'Terry Stop & Frisk Limits',trigger:'Police stop a person based on reasonable suspicion and pat them down.',notes:'A Terry frisk is strictly limited to a pat-down of outer clothing for WEAPONS to protect officer safety. Under the "plain feel" doctrine, an officer can seize contraband (like drugs) during the pat-down ONLY if its illegal nature is immediately apparent without squeezing or manipulating the object.',commonVsModern:'',date:new Date().toISOString()},
  {id:69,subject:'Evidence',rule:'404(b) / MIMIC Non-Character Purposes',trigger:'Prosecution tries to introduce the defendant\'s prior crimes.',notes:'Prior bad acts are inadmissible to show propensity (that they acted in accordance with their character). BUT they are admissible to show Motive, Intent, Mistake (absence of), Identity (modus operandi), or Common scheme/plan. For Identity, the prior act must be a "signature" crime—so unique it acts like a fingerprint.',commonVsModern:'',date:new Date().toISOString()},
  {id:70,subject:'Civil Procedure',rule:'Preliminary Relief Hierarchy (TRO vs Preliminary Injunction)',trigger:'Plaintiff needs the court to stop the defendant from doing something immediately.',notes:'A Temporary Restraining Order (TRO) is an emergency measure, can be issued ex parte (without notice to the other side) if immediate/irreparable harm is shown, and lasts max 14 days. A Preliminary Injunction requires notice and a hearing, and lasts until the end of the trial. Elements for both: likelihood of success on the merits, irreparable harm, balance of equities, public interest.',commonVsModern:'',date:new Date().toISOString()},
  {id:71,subject:'Real Property',rule:'Future Interests: Life Estate and Vested Remainder',trigger:'Grant: "To A for life, then to B and her heirs." B dies before A.',notes:'A has a life estate. B has an indefeasibly vested remainder (because B is an ascertained person and there is no condition precedent). Vested remainders are fully alienable, descendible, and devisable. If B dies before A, B\'s interest passes to B\'s heirs or devisees; it does NOT revert to the grantor.',commonVsModern:'',date:new Date().toISOString()},
  {id:72,subject:'Contracts',rule:'Statute of Frauds & Suretyship (Main-Purpose Rule)',trigger:'A promises to pay B\'s debt if B defaults. A is doing this to protect A\'s own investment.',notes:'Generally, a promise to guarantee another\'s debt (suretyship) must be in writing under the Statute of Frauds. However, under the "Main Purpose" exception, if the promisor\'s primary reason for making the guarantee is to benefit their own economic interest, an oral promise is enforceable.',commonVsModern:'',date:new Date().toISOString()},
  {id:73,subject:'Torts',rule:'Defamation and Publication by Negligent Communication',trigger:'Defendant makes a defamatory statement about Plaintiff, and a third party overhears it.',notes:'"Publication" requires communication to a third party who understands it. It doesn\'t have to be intentional; negligent publication (e.g., speaking too loudly in a crowded room where you should foresee others hearing) is sufficient to establish the publication element for defamation.',commonVsModern:'',date:new Date().toISOString()},
  {id:74,subject:'Civil Procedure',rule:'Diversity Jurisdiction – Aggregation of Claims',trigger:'A plaintiff sues a diverse defendant for a $40,000 breach of contract and a $40,000 unrelated tort.',notes:'A single plaintiff may aggregate ANY AND ALL claims they have against a single defendant to meet the >$75,000 amount-in-controversy requirement for diversity jurisdiction, even if the claims are completely factually unrelated.',commonVsModern:'',date:new Date().toISOString()},
  {id:75,subject:'Real Property',rule:'Mortgages: Deed vs Note; Third-Party Mortgagor',trigger:'A father puts a mortgage on his own house to secure a loan given to his daughter.',notes:'The Promissory Note is the contract for the debt (personal liability). The Mortgage is the security interest in the land. A person can mortgage their land to secure another\'s debt. If the daughter defaults, the bank can foreclose on the father\'s land, but cannot sue the father personally for any deficiency (since he didn\'t sign the note).',commonVsModern:'',date:new Date().toISOString()},
  {id:76,subject:'Evidence',rule:'Nonhearsay Prior Identification (FRE 801(d)(1)(C))',trigger:'A witness identifies the defendant in a lineup, but forgets who did it by the time of trial.',notes:'An out-of-court statement identifying a person as someone the declarant perceived earlier is admissible as SUBSTANTIVE evidence (Nonhearsay) so long as the declarant testifies at trial and is subject to cross-examination about the statement. This applies even if the witness cannot make an in-court identification due to memory loss.',commonVsModern:'',date:new Date().toISOString()},
  {id:77,subject:'Contracts',rule:'Third-Party Beneficiaries vs. Substituted Contracts',trigger:'An agreement is made between two contracting parties where a third-party business or individual stands to profit (e.g., a distributor buying a prize car from a local dealership). Later, the original parties modify the deal or settle for cash, cutting the third party completely out of the transaction.',notes:'* Black-Letter Law: Only intended third-party beneficiaries have standing to enforce a contract; incidental beneficiaries do not. To be an intended beneficiary, the contracting parties must have had the explicit or implied intent to confer a direct benefit on the third party at the time of formation.\\n* Vesting Nuance: Even if a party is an intended beneficiary, their rights must vest before they can sue to prevent a modification or rescission. Rights vest when the beneficiary: (1) manifests assent to the promise in a manner invited or requested by the parties, (2) brings suit to enforce the promise, or (3) materially changes their position in justifiable reliance on the promise.\\n* Bar Exam Trap: If the contract was fundamentally designed to benefit someone else, a party who merely stands to profit is a mere incidental beneficiary. Consequently, they have no standing to challenge the substituted contract (the cash payout arrangement) made between the original parties.',date:new Date().toISOString()},
  {id:78,subject:'Business Entities',rule:'Agent’s Duty of Loyalty & Principal\'s Consent',trigger:'An agent uses a principal’s property for personal enjoyment or outside the strict terms of the employment contract (e.g., a celebrity stylist wearing the client\'s clothes in public). The principal observes this behavior over time and says nothing, but later sues for a breach of fiduciary duty.',notes:'* Black-Letter Law: An agent owes the principal a strict fiduciary duty of loyalty, which includes the duty not to use the principal’s property for the agent\'s own purposes or personal gain without the principal’s consent.\\n* The Consent Exception: A principal can consent to conduct that would otherwise breach the duty of loyalty. This consent does not have to be an express, written waiver; it can be implied through the principal\'s conduct. If a principal has actual knowledge that the agent is using their property and consistently fails to object, the principal\'s silence constitutes ratification or implied consent.\\n* Bar Exam Trap: Do not confuse a lack of monetary damage with a lack of breach. An agent can breach their duty of loyalty even if the principal loses $0. However, the claim fails strictly if the principal\'s repeated failure to object created implied consent, legalizing the actions.',date:new Date().toISOString()},
  {id:79,subject:'Contracts',rule:'UCC Firm Offers vs. Option Contracts',trigger:'A merchant sends a signed email or written communication promising to keep an offer to buy or sell goods open for a specified period (e.g., 60 days). Before that time expires, the merchant tries to raise the price or revoke, but the buyer has already placed an order through an online system.',notes:'* Black-Letter Law (UCC Firm Offer): Under UCC § 2-205, an offer to buy or sell goods is irrevocable if: (1) the offeror is a merchant, (2) the offer is in a signed writing, and (3) it gives explicit assurances that the offer will be held open.\\n* Critical Nuances:\\n  - Consideration: Unlike a common-law option contract, a UCC firm offer does not require consideration to be binding.\\n  - Duration: A firm offer is irrevocable for the time stated, but if no time is stated, for a reasonable time. Crucially, the period of irrevocability cannot exceed 3 months (90 days). If a merchant promises to keep an offer open for 5 months without consideration, it is only legally irrevocable for the first 3 months.\\n  - Electronic Signatures: A typed name, initials, or a digital signature block on an email satisfies the "signed writing" requirement under modern merchant standards.',date:new Date().toISOString()},
  {id:80,subject:'Real Property',rule:'Defeasible Fees & Drafting Conveyances',trigger:'A client wants to convey land to an entity (like a school district) but wants to ensure the land is only used for a specific purpose (e.g., a running track). If the land stops being used for that purpose, the client wants the option or guarantee that ownership will revert.',notes:'* Fee Simple Determinable (FSD):\\n  - Trigger Words: Durational language—"so long as," "while," "during," "until."\\n  - Future Interest: Automatically terminates upon the happening of the event and reverts to the grantor. The grantor holds a Possibility of Reverter.\\n* Fee Simple Subject to Condition Subsequent (FSSCS):\\n  - Trigger Words: Conditional language + right of entry—"but if," "provided that," "on the condition that," coupled with an explicit statement that the grantor may re-enter and retake.\\n  - Future Interest: Does not automatically terminate. The grantor holds a Right of Entry / Power of Termination and must take affirmative legal action to evict the possessor once the condition is broken.',date:new Date().toISOString()},
  {id:81,subject:'Contracts',rule:'Capacity to Contract & Intoxication',trigger:'A person gets heavily intoxicated, draft/sends an offer to sell an asset for cheap, and regrets it the next day after sobering up. However, the buyer has already responded and accepted the offer via email before any revocation was attempted.',notes:'* Black-Letter Law: Voluntary intoxication is a valid defense to contract formation only if: (1) the intoxication was so severe that it deprived the person of the ability to understand the nature and consequences of the transaction, AND (2) the other party had reason to know of the intoxication.\\n* The "Reason to Know" Trap: If a person is thoroughly intoxicated but sends a perfectly coherent, typed email offer from the privacy of their home, the recipient has no visual or contextual clues indicating the intoxication.\\n* Bar Exam Application: If the buyer had no reason to know the owner was drunk, the contract is completely valid. The owner cannot escape the contract based on a lack of capacity.',date:new Date().toISOString()},
  {id:82,subject:'Evidence',rule:'Attorney-Client Privilege & Joint Consultations',trigger:'Prior to filing a personal injury lawsuit, a plaintiff\'s attorney has the plaintiff visit a doctor solely to evaluate damages for the litigation. During a joint discussion, the plaintiff makes a damaging admission. At trial, the defense tries to call the doctor to testify about that statement.',notes:'* Black-Letter Law: The attorney-client privilege protects confidential communications between a client and their attorney (or the attorney\'s representatives) made for the purpose of facilitating legal services.\\n* The Representative Extension (Critical Nuance): When an attorney hires a medical expert or doctor strictly for the purpose of evaluating a case or preparing for litigation (and not for medical treatment), that doctor acts as an agent/representative of the attorney. Therefore, communications made in the presence of that doctor remain entirely confidential under the attorney-client privilege.\\n* Physician-Patient Privilege Distinction: The physician-patient privilege only applies when a patient consults a doctor for medical diagnosis or treatment. It does not apply to purely legal evaluations.',date:new Date().toISOString()},
  {id:83,subject:'Evidence',rule:'The Best Evidence Rule & Personal Knowledge',trigger:'A party attempts to introduce a scanned copy or duplicate of a receipt into evidence. Simultaneously, they call an employee to testify about the specific contents or data written on the original receipt, even though the employee was not present for the transaction and is simply reading or repeating what the document says.',notes:'* Best Evidence Rule: Requires the production of an original writing, recording, or photograph to prove its contents. However, under FRE 1003, a duplicate/scanned copy is perfectly admissible to the same extent as an original unless a genuine question is raised about the original\'s authenticity or it would be unfair to admit it.\\n* Personal Knowledge Requirement: A witness may not testify to a matter unless evidence is introduced sufficient to support a finding that the witness has personal knowledge of the matter (FRE 602). A witness cannot simply look at a document they have no personal involvement with and testify to its underlying factual contents.',date:new Date().toISOString()},
  {id:84,subject:'Evidence',rule:'Impeachment by Evidence of a Criminal Conviction (FRE 609)',trigger:'A witness testifies at trial. After they leave the stand, the opposing party attempts to introduce extrinsic evidence proving the witness was convicted of a crime involving dishonesty 11 years ago, without ever asking the witness about it while they were on the stand.',notes:'* Crimes of Dishonesty (No Discretion): Under FRE 609(a)(2), any prior conviction for a crime of dishonesty or false statement (e.g., perjury, fraud, embezzlement) must be admitted for impeachment purposes, regardless of whether it was a felony or misdemeanor, and the judge cannot balance prejudice under Rule 403.\\n* The 10-Year Rule: If more than 10 years have passed since the witness\'s conviction or release from confinement (whichever is later), the conviction is stale. It is only admissible if: (1) its probative value substantially outweighs its prejudicial effect, and (2) the proponent gives reasonable written notice.\\n* Extrinsic Evidence Nuance: Unlike prior bad acts under Rule 608(b), a criminal conviction used to impeach a witness\'s character for truthfulness may be proved by extrinsic evidence (like a certified record), and there is no strict requirement that the witness be confronted first on the stand.',date:new Date().toISOString()},
  {id:85,subject:'Real Property',rule:'Cotenants\' Rights to Possession, Repairs, and Taxes',trigger:'Two relatives own a home as tenants in common. One lives out of state, and they agree the local relative will occupy the house. The occupying relative pays the property taxes (which are less than the home\'s fair rental value) and pays for an emergency plumbing repair. Later, the occupying relative demands 50% reimbursement from the out-of-state cotenant.',notes:'* Right to Possession: Each cotenant has an absolute right to possess and enjoy the entire property. An occupying cotenant does not owe rent to non-occupying cotenants unless there has been an "ouster".\\n* Property Taxes / Mortgages: A cotenant who pays more than their share can generally seek contribution. Exception: If the occupying cotenant is the only one enjoying the property, they cannot get a reimbursement for taxes if the financial value of their sole occupancy (rental value) exceeds the amount paid for taxes.\\n* Repairs & Improvements: A cotenant has no right to compel contribution from other cotenants for necessary repairs or improvements in the absence of an express agreement. Instead, the cotenant who paid for repairs receives a credit or adjustment during a later partition action.',date:new Date().toISOString()},
  {id:86,subject:'Real Property',rule:'Future-Advances Mortgages & Priority',trigger:'A bank records a construction loan mortgage that explicitly states the bank will disburse money in monthly installments as building progresses. A third-party creditor later records a judgment lien against the borrower. Afterward, the bank makes its scheduled monthly advances to the borrower.',notes:'* Black-Letter Law: A future-advances mortgage secures a loan where funds are paid out over time rather than all at once. The priority of these later payments against intervening liens depends entirely on whether the advances are obligatory or optional.\\n* Obligatory Advances: If the bank is legally contractually committed to making the line of credit advances, the future advances retain the original recording date of the mortgage. They have absolute priority over any junior lien recorded in the interim.\\n* Optional Advances: If the disbursements are completely at the bank\'s discretion, an advance made after the bank receives notice of an intervening judgment lien loses priority to that junior lien.',date:new Date().toISOString()},
  {id:87,subject:'Civil Procedure',rule:'Jury Trial Demand upon Removal',trigger:'A case is removed from state court to federal district court, and a party wants a jury trial but didn\'t demand it in state court.',notes:'Federal rules (FRCP 81(c)) govern the procedure for demanding a jury trial after removal. Even if state law deems the right waived because it wasn\'t in the initial pleading, a party can preserve their 7th Amendment right by serving a written demand within the specific window provided under federal rules after removal.',commonVsModern:'',date:new Date().toISOString()},
  {id:88,subject:'Civil Procedure',rule:'Choice of Law Rules Upon Venue Transfer',trigger:'A diversity case is transferred from one proper federal venue to another under 28 U.S.C. § 1404(a).',notes:'The receiving court must apply the substantive law—including the choice-of-law rules—that would have been applied by the original (transferor) court.',commonVsModern:'',date:new Date().toISOString()},
  {id:89,subject:'Constitutional Law – Individual Rights',rule:'Exactions (Fifth Amendment Takings)',trigger:'A local government conditions the approval of a land-development or building permit on a landowner\'s promise to dedicate property or resources to public use.',notes:'To avoid being classified as an unconstitutional Fifth Amendment taking, the government bears the burden of demonstrating: (1) An essential nexus between the imposed condition and a legitimate government interest, and (2) A rough proportionality (supported by individualized and quantifiable findings) between the impact of the condition on the landowner and the proposed development\'s impact on the community.',commonVsModern:'',date:new Date().toISOString()},
  {id:90,subject:'Constitutional Law – Individual Rights',rule:'Procedural Due Process & Standards of Proof',trigger:'An individual faces deprivation of life, liberty, or property by the government, such as a judge with a conflict of interest, or termination of parental rights.',notes:'Neutral Decision-Maker: Due process requires a neutral, unbiased decision-maker. A judge\'s failure to recuse themselves when they have a direct personal stake violates this.\\nTermination of Parental Rights: Because the private interest in maintaining parental relationships is deeply fundamental, the Mathews v. Eldridge balancing test requires a higher standard of proof than a mere preponderance of the evidence. A state statute permitting permanent termination of parental rights based only on a preponderance of the evidence violates procedural due process; it typically requires clear and convincing evidence.',commonVsModern:'',date:new Date().toISOString()},
  {id:91,subject:'Constitutional Law – Individual Rights',rule:'Equal Protection Against the Federal Government',trigger:'The federal government utilizes suspect classifications like race or national origin (e.g., in federal contract preferences).',notes:'While the Fourteenth Amendment\'s Equal Protection Clause explicitly applies to states, the Due Process Clause of the Fifth Amendment contains an equal protection component that applies identical strict scrutiny standards to the federal government.',commonVsModern:'',date:new Date().toISOString()},
  {id:92,subject:'Real Property',rule:'Inter Vivos Deeds vs. Wills (Delivery Presumptions)',trigger:'A grantor executes a deed but leaves it with an attorney, and later writes a conflicting will before passing away.',notes:'A valid inter vivos conveyance requires execution, delivery, and acceptance. Recording a deed raises a strong, rebuttable presumption of delivery, even if the physical deed remains with an attorney and is not handed to the grantee before the grantor\'s death. Because a deed takes effect immediately upon delivery, a subsequent or conflicting testamentary gift in a will is invalid regarding that property.',commonVsModern:'',date:new Date().toISOString()},
  {id:93,subject:'Real Property',rule:'Easement Classifications',trigger:'A question tests the nature of an easement (e.g., who it benefits, what it allows, or how it was created).',notes:'In Gross: Benefits the holder personally rather than a parcel of land; burden transfers with servient estate, benefit does not automatically attach to land.\\nAffirmative vs. Negative: Affirmative allows active use of servient estate; negative restricts servient owner\'s lawful use of their land.\\nCreation: Can be express (Statute of Frauds), irrevocable license (estoppel), or implied (necessity/prior use).',commonVsModern:'',date:new Date().toISOString()},
  {id:94,subject:'Constitutional Amendments',rule:'4th Amendment - Threshold Issues',trigger:'Police search a location or item and defendant attempts to challenge it.',notes:'• Does the defendant have standing? (reasonable expectation of privacy — Katz test)\\n• Was there government action? (private searches don\'t trigger 4th Amendment)',commonVsModern:'',date:new Date().toISOString()},
  {id:95,subject:'Constitutional Amendments',rule:'4th Amendment - Searches',trigger:'Police conduct a search with or without a warrant.',notes:'• Warrant requirement — probable cause + particularity\\n• Exceptions to warrant requirement:\\n  - Consent (voluntary, no coercion)\\n  - Search incident to lawful arrest (Chimel — person + grabbable area)\\n  - Plain view (lawful vantage point + immediately apparent)\\n  - Exigent circumstances (hot pursuit, emergency, evanescent evidence)\\n  - Automobile exception (probable cause to believe contraband)\\n  - Terry stop & frisk (reasonable suspicion + safety)\\n  - Inventory search\\n  - Protective sweep',commonVsModern:'',date:new Date().toISOString()},
  {id:96,subject:'Constitutional Amendments',rule:'4th Amendment - Special Contexts',trigger:'Police search a phone, tracking data, or special administrative area.',notes:'• Third-party doctrine (phone records, bank records — no REP)\\n• Digital/cell phones → Riley (warrant required for cell phone search incident to arrest)\\n• GPS tracking → Jones/Carpenter (prolonged surveillance = search)\\n• Curtilage vs. open fields\\n• Administrative/school searches (lower standard)',commonVsModern:'',date:new Date().toISOString()},
  {id:97,subject:'Constitutional Amendments',rule:'4th Amendment - Seizures',trigger:'Police stop or detain an individual.',notes:'• When does a seizure occur? (reasonable person feels free to leave)\\n• Terry stop vs. arrest — level of suspicion required\\n• Pretextual stops (Whren)',commonVsModern:'',date:new Date().toISOString()},
  {id:98,subject:'Constitutional Amendments',rule:'4th Amendment - Exclusionary Rule',trigger:'Evidence is obtained in violation of the 4th Amendment.',notes:'• Evidence obtained in violation → suppressed\\n• Exceptions: Good faith, inevitable discovery, independent source, attenuation (Wong Sun)\\n• Fruit of the poisonous tree',commonVsModern:'',date:new Date().toISOString()},
  {id:99,subject:'Constitutional Amendments',rule:'5th Amendment - Self-Incrimination',trigger:'Police question a suspect.',notes:'• Miranda warnings — trigger: custody + interrogation\\n• Custody = reasonable person would not feel free to leave\\n• Interrogation = express questioning or its functional equivalent\\n• Invocation — must be clear and unambiguous\\n• Waiver — knowing, voluntary, intelligent\\n• Public safety exception (Quarles)\\n• Miranda applies to testimonial evidence only (not blood, DNA, handwriting)',commonVsModern:'',date:new Date().toISOString()},
  {id:100,subject:'Constitutional Amendments',rule:'5th Amendment - Double Jeopardy',trigger:'Defendant is prosecuted multiple times for the same or similar offense.',notes:'• Attaches when jury is sworn in (or first witness sworn in a bench trial)\\n• Same offense test — Blockburger (two offenses = same if each doesn\'t require proof of element the other doesn\'t)\\n• Separate sovereigns exception (state + federal prosecution OK)\\n• Exceptions: mistrial for manifest necessity, hung jury, appeal by defendant',commonVsModern:'',date:new Date().toISOString()},
  {id:101,subject:'Constitutional Amendments',rule:'5th Amendment - Takings Clause',trigger:'Government seizes or heavily regulates private property.',notes:'• Private property taken for public use → just compensation required\\n• Physical taking vs. regulatory taking (Penn Central)\\n• Per se taking: permanent physical occupation; total economic wipeout\\n• Trigger: gov\'t action that destroys all economic value',commonVsModern:'',date:new Date().toISOString()},
  {id:102,subject:'Constitutional Amendments',rule:'5th Amendment - Grand Jury / Due Process (5th)',trigger:'Defendant is indicted for a federal serious crime.',notes:'• Federal right to grand jury indictment for serious crimes\\n• Not incorporated to states',commonVsModern:'',date:new Date().toISOString()},
  {id:103,subject:'Constitutional Amendments',rule:'6th Amendment - Right to Counsel',trigger:'Defendant is formally charged and interacts with police or court.',notes:'• Attaches at all critical stages after formal charges\\n• Critical stages: arraignment, preliminary hearing, post-indictment interrogation, plea, sentencing\\n• Does NOT attach during pre-charge investigation (Rothgery line)\\n• Deliberate elicitation standard post-attachment (Massiah)\\n• Offense-specific — attaches only to the charged offense',commonVsModern:'',date:new Date().toISOString()},
  {id:104,subject:'Constitutional Amendments',rule:'6th Amendment - Effective Assistance of Counsel',trigger:'Defendant claims their lawyer made a mistake that affected the trial or plea.',notes:'• Strickland test: (1) deficient performance + (2) prejudice\\n• Prejudice = reasonable probability of different outcome\\n• Applies at trial AND plea bargaining (Lafler/Frye)',commonVsModern:'',date:new Date().toISOString()},
  {id:105,subject:'Constitutional Amendments',rule:'6th Amendment - Right to Jury Trial',trigger:'Defendant is charged with an offense and requests a jury.',notes:'• Serious offenses (> 6 months potential imprisonment)\\n• 6-person jury minimum; must be unanimous (federal + Ramos → state)\\n• Trigger: petty vs. serious offense distinction',commonVsModern:'',date:new Date().toISOString()},
  {id:106,subject:'Constitutional Amendments',rule:'6th Amendment - Speedy Trial',trigger:'A significant delay occurs before the defendant goes to trial.',notes:'• Barker v. Wingo balancing: length of delay, reason, assertion of right, prejudice',commonVsModern:'',date:new Date().toISOString()},
  {id:107,subject:'Constitutional Amendments',rule:'6th Amendment - Confrontation Clause',trigger:'Prosecution attempts to introduce an out-of-court statement without the declarant present.',notes:'• Right to cross-examine witnesses\\n• Crawford — testimonial hearsay requires opportunity to cross-examine\\n• Dying declarations exception',commonVsModern:'',date:new Date().toISOString()},
  {id:108,subject:'Constitutional Amendments',rule:'6th Amendment - Other 6th Rights',trigger:'Issues regarding trial transparency or witnesses.',notes:'• Public trial\\n• Notice of charges\\n• Compulsory process (subpoena witnesses)',commonVsModern:'',date:new Date().toISOString()},
  {id:109,subject:'Constitutional Amendments',rule:'14th Amendment - Due Process — Procedural',trigger:'Government deprives life, liberty, or property.',notes:'• Liberty interests: physical freedom, fundamental rights, protected state-created interests\\n• Property interests: legitimate claim of entitlement\\n• Process required: Mathews v. Eldridge balancing (private interest + risk of error + gov\'t interest)',commonVsModern:'',date:new Date().toISOString()},
  {id:110,subject:'Constitutional Amendments',rule:'14th Amendment - Due Process — Substantive',trigger:'Government restricts a right for all people.',notes:'• Fundamental rights → strict scrutiny (necessary to compelling interest)\\n• Non-fundamental → rational basis (rationally related to legitimate interest)\\n• Fundamental rights: voting, travel, privacy, marriage, contraception, family relations\\n• Dobbs — abortion no longer fundamental right',commonVsModern:'',date:new Date().toISOString()},
  {id:111,subject:'Constitutional Amendments',rule:'14th Amendment - Equal Protection',trigger:'Government treats different classes of people differently.',notes:'• Strict scrutiny → race, national origin, alienage (most cases), fundamental rights\\n• Intermediate scrutiny → sex/gender, legitimacy\\n• Rational basis → everything else (age, disability, wealth, sexual orientation historically — post-Obergefell unclear)\\n• Trigger facts: facial classification vs. facially neutral law with discriminatory intent + impact (Washington v. Davis)',commonVsModern:'',date:new Date().toISOString()},
  {id:112,subject:'Constitutional Amendments',rule:'14th Amendment - Incorporation',trigger:'A state infringes on a right guaranteed by the Bill of Rights.',notes:'• Bill of Rights applied to states through 14th Amendment Due Process\\n• Selective incorporation — right must be fundamental to ordered liberty\\n• Nearly all rights now incorporated (grand jury indictment is a key exception)',commonVsModern:'',date:new Date().toISOString()},
  {id:113,subject:'Constitutional Amendments',rule:'14th Amendment - State Action Doctrine',trigger:'A private individual or corporation violates a constitutional right.',notes:'• 14th Amendment only applies to government actors\\n• Exceptions: public function doctrine, entanglement/nexus',commonVsModern:'',date:new Date().toISOString()},
];
